<template>
  <div class="pagination-container">
    <!-- current-page: 当前页数，支持 v-model 双向绑定 -->
    <!-- page-size: 每页显示条目个数，支持 v-model 双向绑定 -->
    <!-- page-sizes: 每页显示个数选择器的选项设置 -->
    <!-- pager-count: 设置最大页码按钮数。 页码按钮的数量，当总页数超过该值时会折叠 -->
    <!-- background: 是否为分页按钮添加背景色 -->
    <!-- layout: 组件布局，子组件名用逗号分隔 -->
    <!-- total: 总条目数 -->
    <!-- @size-change: pageSize 改变时触发 -->
    <!-- @current-change: current-change 改变时触发 -->
    <el-pagination
      v-model:current-page="pageNum"
      v-model:page-size="pageSize"
      v-loading.fullscreen.lock="loading"
      element-loading-spinner="el-icon-loading"
      background
      :layout="layout"
      :page-sizes="pageSizes"
      :total="page.total || 0"
      :pager-count="pagerCount"
      v-bind="$attrs"
      @size-change="handleSizeChange"
      @current-change="handleCurrentChange"
    />
  </div>
</template>

<script lang="ts">
import { defineComponent, reactive, toRefs, watch } from 'vue';

export default defineComponent({
  name: 'TPaging',
  props: {
    page: {
      required: true,
      type: Object,
      default: () => ({
        pageNum: 1,
        pageSize: 10,
        total: 0,
      }),
    },
    // 每页显示个数选择器的选项设置
    pageSizes: {
      required: false,
      type: Array,
      default: () => [5, 10, 20, 50, 100],
    },
    // 组件布局，子组件名用逗号分隔
    layout: {
      type: String,
      default: 'total, sizes, prev, pager, next, jumper',
    },
    // 总页数 total 和 page-count 设置任意一个就可以达到显示页码的功能；如果要支持 page-sizes 的更改，则需要使用 total 属性
    pagerCount: {
      required: false,
      type: Number,
      default: 7,
    },
    /*
     * autoScroll: {
     *   type: Boolean,
     *   default: true,
     * },
     */
  },
  emits: ['update:page-num', 'update:page-size', 'handle-search'],
  setup(props, { emit }) {
    console.log(props, 'pageProps');
    // 响应式数据
    const state = reactive({
      // 当前页码
      currentPage: 1,
      // 页码
      pageNum: props.page.pageNum,
      // 每页数据条数
      pageSize: 10,
      // 是否显示加载动画
      loading: false,
    });

    /**
     * 更改每页数量
     * @param val 页码
     */
    const handleSizeChange = async (val: number) => {
      state.loading = true;
      // 更新每页数据条数及页码
      emit('update:page-size', val);
      emit('update:page-num', props.page.pageNum);
      // 告诉父组件，分页参数更新完成，可以执行搜索了
      await emit('handle-search');
      state.loading = false;

      // scrollTo(0, 800);
    };

    /**
     * 翻页
     * @param val 页码
     */
    const handleCurrentChange = async (val: number) => {
      state.loading = true;
      // 更新每页数据条数及页码
      emit('update:page-size', props.page.pageSize);
      emit('update:page-num', val);
      // 告诉父组件，分页参数更新完成，可以执行搜索了
      await emit('handle-search');
      state.loading = false;

      /*
       * if (props.autoScroll) {
       *    scrollTo(0, 800);
       * }
       */
    };

    // 监测外部页码变化
    watch(
      () => props.page.pageNum,
      async (newValue) => {
        state.pageNum = newValue;
      },
    );

    watch(
      () => props.page.pageSize,
      async (newValue) => {
        state.pageSize = newValue;
      }, {
        immediate: true,
      },
    );

    return {
      ...toRefs(state),
      handleSizeChange,
      handleCurrentChange,
    };
  },
});
</script>
